import{C as e,o as t,c as l,a5 as a,E as o}from"./chunks/framework.CW28V7p_.js";const d=JSON.parse('{"title":"4. Token accounts & ATA","description":"","frontmatter":{},"headers":[],"relativePath":"module-2/4-tokens-ata.md","filePath":"module-2/4-tokens-ata.md","lastUpdated":1780937944000}'),p={name:"module-2/4-tokens-ata.md"},c=Object.assign(p,{setup(r){const n={id:"m2-4-tokens-ata",title:"🧠 Mini-check: Tokens & ATA",intro:"3 питання — це ВАЖЛИВО для DoubleZero rewards setup.",questions:[{type:"diagnose",q:"Тобі дали pubkey 9mP3sXyzAbc... як кандидат для --rewards-token-owner. Як перевірити чи це SOL wallet (підходить) чи token account/ATA (не підходить)?",options:["solana account 9mP3sXyzAbc... і подивитись на Owner field","solana balance 9mP3sXyzAbc... — якщо балас > 0 SOL, то wallet","spl-token accounts --owner 9mP3sXyzAbc...","Не можна перевірити без access до private key"],correct:[0],explanation:"Тільки solana account дає Owner field. Якщо Owner = 11111... (System Program) → SOL wallet, годиться. Якщо Owner = Tokenkeg... → ATA/token account, НЕ годиться. Balance — теж є у wallet AND token accounts, не decisive. spl-token accounts — дає token accounts які owns цей wallet, но не тип самого pubkey. Module 2.4."},{type:"mcq",q:"Що з цього вірно про Associated Token Account (ATA)? (обери всі)",options:["ATA address derives deterministically з (owner_wallet, token_mint)","Кожна пара (wallet, mint) має тільки одну ATA","ATA можна створити будь-ким — не потрібен власник wallet signнути","Один wallet може мати кілька ATAs для різних tokens"],correct:[0,1,2,3],explanation:'Усі 4 правильні. ATA = deterministic PDA з seeds (wallet, mint, token_program). One per (wallet, mint) — це і означає "associated". Permissionless creation — будь-хто може створити ATA для будь-якого pair (платить rent). Wallet має ATA per token type — JTO ATA, USDC ATA, JitoSOL ATA, etc.'},{type:"command",q:"Як подивитись всі token accounts які owns певний wallet (наприклад для аудиту чийогось portfolio)? Напиши команду.",accepts:["spl-token accounts --owner WALLET_PUBKEY","spl-token accounts --owner WALLET_PUBKEY --url mainnet-beta","solana spl-token accounts --owner WALLET_PUBKEY"],ideal:"spl-token accounts --owner WALLET_PUBKEY",explanation:"spl-token accounts --owner <PUBKEY> виводить всі token accounts які owned by цей wallet. Кожен рядок: token mint, balance, account pubkey (це і є ATA). Module 2.4."}]};return(k,s)=>{const i=e("Quiz");return t(),l("div",null,[s[0]||(s[0]=a("",63)),o(i,{data:n}),s[1]||(s[1]=a("",6))])}}});export{d as __pageData,c as default};
